class NuclearGridOptimizer:
    def calculate_peak_arbitrage(self, base_load_cost: float, peak_demand_price: float, storage_loss: float) -> float:
        """Batarya depolama ve arbitraj marjını hesaplar."""
        return (peak_demand_price * (1.0 - storage_loss)) - base_load_cost

